        public static <T> Result<T> err(Exception error) {
            return new Result<>(null, error);
        }

        public boolean isOk() {
            return error == null;
        }

        public boolean isErr() {
            return error != null;
        }

        public T unwrap() {
            if (isErr()) throw new IllegalStateException("Called unwrap on error result", error);
            return value;
        }

        public Exception getError() {
            return error;
        }
    }
}

